{"contents":"{
  "name": "SAPManage",
  "description": "Probe and report SAP system capabilities. Use this BEFORE attempting operations that depend on optional features (abapGit, RAP/CDS, AMDP, HANA, UI5/Fiori, CTS transports, FLP customization). Also handles package (DEVC) lifecycle operations.\n\nActions:\n- \"features\": Get cached feature status from last probe (fast, no SAP round-trip). Returns which features are available, their mode (auto/on/off), and when they were last probed.\n- \"probe\": Re-probe the SAP system now (runs feature probes, auth checks, and ADT discovery refresh). Use this on first use or if you suspect feature availability has changed.\n- \"cache_stats\": Show object cache health and warmup state.\n- \"flp_list_catalogs\": List FLP business catalogs.\n- \"flp_list_groups\": List FLP groups.\n- \"flp_list_tiles\": List tiles in a catalog (requires \"catalogId\").\n- \"create_package\": Create a package (DEVC) via ADT packages API.\n- \"delete_package\": Delete an existing package.\n- \"flp_create_catalog\": Create a business catalog (requires \"domainId\", \"title\").\n- \"flp_create_group\": Create a group (requires \"groupId\", \"title\").\n- \"flp_create_tile\": Create a tile in a catalog (requires \"catalogId\", \"tile\").\n- \"flp_add_tile_to_group\": Add a catalog tile to a group (requires \"groupId\", \"catalogId\", \"tileInstanceId\").\n- \"flp_delete_catalog\": Delete a business catalog (requires \"catalogId\").\n\nReturns JSON with features, each having: id, available (bool), mode, message, and probedAt timestamp. Also returns systemType (\"btp\" or \"onprem\") for understanding available capabilities. \"available: false\" means do NOT attempt operations that depend on it.",
  "arguments": {
    "type": "object",
    "properties": {
      "action": {
        "type": "string",
        "enum": [
          "features",
          "probe",
          "cache_stats",
          "flp_list_catalogs",
          "flp_list_groups",
          "flp_list_tiles",
          "create_package",
          "delete_package",
          "change_package",
          "flp_create_catalog",
          "flp_create_group",
          "flp_create_tile",
          "flp_add_tile_to_group",
          "flp_delete_catalog"
        ],
        "description": "Action to execute. Read actions: features, probe, cache_stats, flp_list_catalogs, flp_list_groups, flp_list_tiles. Mutating package/FLP actions require writable safety config and write scope in authenticated mode."
      },
      "name": {
        "type": "string",
        "description": "Package name (required for create_package and delete_package)."
      },
      "description": {
        "type": "string",
        "description": "Package description (required for create_package)."
      },
      "superPackage": {
        "type": "string",
        "description": "Parent package for create_package (defaults to empty root package)."
      },
      "softwareComponent": {
        "type": "string",
        "description": "Software component for create_package (default: LOCAL)."
      },
      "transportLayer": {
        "type": "string",
        "description": "Transport layer for create_package (optional; required by some transportable landscapes)."
      },
      "packageType": {
        "type": "string",
        "enum": [
          "development",
          "structure",
          "main"
        ],
        "description": "Package type for create_package (default: development)."
      },
      "transport": {
        "type": "string",
        "description": "Optional transport request (corrNr) for create_package, delete_package, or change_package."
      },
      "objectUri": {
        "type": "string",
        "description": "ADT URI of the object to move (e.g., /sap/bc/adt/oo/classes/zcl_my_class). If not provided, resolved automatically from objectName + objectType via search."
      },
      "objectType": {
        "type": "string",
        "description": "ADT object type (e.g., CLAS/OC, DDLS/DF, PROG/P). Required for change_package."
      },
      "objectName": {
        "type": "string",
        "description": "Object name to move (e.g., ZCL_MY_CLASS). Required for change_package."
      },
      "oldPackage": {
        "type": "string",
        "description": "Current package of the object. Required for change_package."
      },
      "newPackage": {
        "type": "string",
        "description": "Target package to move the object to. Required for change_package."
      },
      "catalogId": {
        "type": "string",
        "description": "FLP catalog identifier — accepts either full ID (X-SAP-UI2-CATALOGPAGE:MY_CAT) or domain ID (MY_CAT). Required for flp_list_tiles, flp_create_tile, flp_add_tile_to_group, flp_delete_catalog."
      },
      "groupId": {
        "type": "string",
        "description": "FLP group/page identifier (required for flp_create_group, flp_add_tile_to_group)."
      },
      "title": {
        "type": "string",
        "description": "Title for FLP catalog/group creation."
      },
      "domainId": {
        "type": "string",
        "description": "Domain ID for FLP catalog creation (e.g., ZARC1_SALES)."
      },
      "tileInstanceId": {
        "type": "string",
        "description": "Tile instance ID in the source catalog (required for flp_add_tile_to_group)."
      },
      "tile": {
        "type": "object",
        "description": "Tile definition for flp_create_tile.",
        "properties": {
          "id": {
            "type": "string",
            "description": "Tile ID (client-side logical id)."
          },
          "title": {
            "type": "string",
            "description": "Display title."
          },
          "icon": {
            "type": "string",
            "description": "Optional icon URI."
          },
          "semanticObject": {
            "type": "string",
            "description": "Semantic object for intent navigation."
          },
          "semanticAction": {
            "type": "string",
            "description": "Semantic action for intent navigation."
          },
          "url": {
            "type": "string",
            "description": "Optional target URL."
          },
          "subtitle": {
            "type": "string",
            "description": "Optional subtitle text."
          },
          "info": {
            "type": "string",
            "description": "Optional info text."
          }
        },
        "required": [
          "id",
          "title",
          "semanticObject",
          "semanticAction"
        ]
      }
    },
    "required": [
      "action"
    ]
  }
}","totalLinesInFile":149}

